from polynomial import poly
from auxiliary import byte_decode, byte_encode
from ntt import NTT

def test_poly_mul_768():
    A_bytes = bytes.fromhex("")

    k = 3
    poly_len = 384
    
    A = []
    for i in range(k):
        row = []
        for j in range(k):
            start = (i * k + j) * poly_len
            poly_coeffs = byte_decode(A_bytes[start:start+poly_len], 12)
            row.append(poly(poly_coeffs))
        A.append(row)
    
    s_bytes = bytes.fromhex("")

    s0 = poly(NTT(byte_decode(s_bytes[0:384], 12)))
    s1 = poly(NTT(byte_decode(s_bytes[384:768], 12)))
    s2 = poly(NTT(byte_decode(s_bytes[768:1152], 12)))

    s_hat = [s0, s1, s2]

    e_bytes = bytes.fromhex("")

    e0 = poly(NTT(byte_decode(e_bytes[0:384], 12)))
    e1 = poly(NTT(byte_decode(e_bytes[384:768], 12)))
    e2 = poly(NTT(byte_decode(e_bytes[768:1152], 12)))

    e_hat = [e0, e1, e2]

     # A * s
    As = []
    for row in range(3):
        p = poly([0] * 256)
        for col in range(3):
            tmp = A[row][col] * s_hat[col]
            p += tmp
        As.append(p)

    # + e
    t_hat = []
    for row in range(3):
        t_hat.append(As[row] + e_hat[row])

    t_hat_coeff = [c for p in t_hat for c in p.coeff]
    t_hat_bytes = byte_encode(t_hat_coeff, 12)

    expected_t_bytes = bytes.fromhex("")
    
    assert t_hat_bytes == expected_t_bytes

def test_poly_add():
    a = [3328, 1, 0, 2000]
    b = [2, 3328, 1, 2000]
    expected = [1, 0, 1, 671]

    polyResult = poly(a) + poly(b)
    assert expected == polyResult.coeff

def test_poly_sub():
    a = [3328, 1, 0, 2000]
    b = [2, 3328, 1, 2000]
    expected = [3326, 2, 3328, 0]

    polyResult = poly(a) - poly(b)
    assert expected == polyResult.coeff 

def test_poly_reduce():
    input = [5000, 10000, 15000, 20000]
    expected = [1671, 13, 1684, 26]
    polyI = poly(input)
    polyI.poly_reduce()
    assert expected == polyI.coeff